// Store the telegram chat ID from the trigger message
const chatId = String($json.message?.chat?.id || '5363500098').trim();
return [{ json: { telegramChatId: chatId } }];

// Merge resume into each pending row and check if there are any rows at all
const str = (v) => {
  if (v === null || v === undefined || v === false || v === true) return '';
  const s = String(v).trim();
  return (s === 'null' || s === 'undefined' || s === 'false' || s === 'N/A') ? '' : s;
};

const resumeRaw = str($input.first().json.content);
const resumeSnippet = resumeRaw.replace(/\s+/g,' ').trim().substring(0, 800);

const pendingRows = $('Read: All Pending Jobs').all();
const chatId = str($('Capture Telegram Chat ID').first().json.telegramChatId);

if (pendingRows.length === 0 || (pendingRows.length === 1 && !str(pendingRows[0].json['Company']))) {
  return [{ json: { _skip: true, telegramChatId: chatId } }];
}

return pendingRows
  .filter(r => str(r.json['Company']).length > 0)
  .map(r => ({
    json: {
      ...r.json,
      // Normalize column names — sheet uses both spaced and underscored versions
      'Company':          str(r.json['Company']),
      'Job Title':        str(r.json['Job Title']),
      'Location':         str(r.json['Location']),
      'Salary':           str(r.json['Salary']),
      'Job Type':         str(r.json['Job_type ']) || str(r.json['Job Type']) || str(r.json['Job_type']),
      'Job URL':          str(r.json['Job URL']),
      'Company Website':  str(r.json['Company_Website']) || str(r.json['Company Website']),
      'Company Domain':   str(r.json['Company_Domain'])  || str(r.json['Company Domain']),
      'Job Description':  str(r.json['Job_Description']) || str(r.json['Job Description']),
      'Resume Snippet':   resumeSnippet,
      _telegramChatId:    chatId
    }
  }));

const rows = $input.all();
const total   = rows.length;
const sent    = rows.filter(r => String(r.json['Send Status'] || '').toLowerCase() === 'sent').length;
const failed  = rows.filter(r => String(r.json['Send Status'] || '').toLowerCase().startsWith('failed')).length;
const skipped = rows.filter(r => String(r.json['Send Status'] || '').toLowerCase().includes('skipped')).length;
const pending = rows.filter(r => String(r.json['Send Status'] || '').toLowerCase() === 'pending').length;

const successRate = sent + failed > 0 ? Math.round((sent / (sent + failed)) * 100) : 0;

const sentList = rows
  .filter(r => String(r.json['Send Status'] || '').toLowerCase() === 'sent')
  .slice(0, 15)
  .map(r => '  • ' + String(r.json['Company'] || '') + ' — ' + String(r.json['Recruiter Email'] || 'email sent'))
  .join('\n');

const sheetUrl = 'https://docs.google.com/spreadsheets/d/1ObbN-YUb-IZJjlion3sjDk2lioSR5v3kRwPPXotvdTE';

const message =
  'Pending Emails Run Complete!\n\n' +
  'Results:\n' +
  '  Sent:         ' + sent + '\n' +
  '  Failed:       ' + failed + '\n' +
  '  Skipped:      ' + skipped + '\n' +
  '  Still Pending: ' + pending + '\n' +
  '  Success Rate: ' + successRate + '%\n' +
  '  Total Rows:   ' + total + '\n\n' +
  (sentList ? 'Emails Sent To:\n' + sentList + '\n\n' : '') +
  'View Sheet:\n' + sheetUrl;

const chatId = String($('Capture Telegram Chat ID').first().json.telegramChatId || '5363500098');

return [{ json: { message, telegramChatId: chatId } }];

const str = (v) => {
  if (v === null || v === undefined || v === false) return '';
  return String(v).trim();
};

const items = $input.all();
const results = [];

for (const item of items) {
  const sheetData = $('Loop: One Pending Job at a Time').item.json;

  const company       = str(sheetData['Company']);
  const jobTitle      = str(sheetData['Job Title']);
  const jobUrl        = str(sheetData['Job URL']);
  const location      = str(sheetData['Location']);
  const salary        = str(sheetData['Salary']);
  const domain        = str(sheetData['Company Domain']);
  const website       = str(sheetData['Company Website']);
  const jobType       = str(sheetData['Job Type']);
  const jobDesc       = str(sheetData['Job Description']);
  const resumeSnippet = str(sheetData['Resume Snippet']);

  // ── Call Claude API ───────────────────────────────────────────────────────
  let aiResult = {};
  try {
    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 1000,
        system:
          'You are an expert job application assistant. Your only job is to help Smit Chavda — a software developer — get interviews by writing excellent cold outreach emails.\n\n' +
          'You will receive job details and Smit\'s resume. Do exactly TWO things and return ONLY a raw JSON object with no markdown, no code fences, no extra text before or after.\n\n' +
          'TASK 1 — Find the best recruiter / HR email\n' +
          'Use the Company Domain field.\n' +
          '- If Company Domain is empty: infer the likely domain from the Company Name (e.g. Infosys → infosys.com, Zoho → zoho.com, a startup like "AppCraft" → appcraft.io or appcraft.com)\n' +
          '- Build the email using these prefixes in priority order: careers@ → hr@ → jobs@ → talent@ → recruiting@ → apply@ → hello@\n' +
          '- For startups or small companies with no obvious domain: prefer hello@ or hi@ as a fallback\n' +
          '- Never guess random domains — if very uncertain, use hr@companyname.com as fallback\n' +
          '- Set email_confidence: "high" = domain was provided | "medium" = inferred from company name | "low" = very uncertain\n\n' +
          'TASK 2 — Write a world-class cold outreach email\n' +
          'The email must be professional, personalized, and compelling. A real hiring manager should want to read it.\n\n' +
          'STRUCTURE (follow exactly):\n' +
          '1. Subject line — specific, mentions the role and company, max 10 words\n' +
          '2. Opening line — a specific, genuine hook: reference something real from the job description or the company\'s domain/industry. Show you understand what they do.\n' +
          '3. Body paragraph 1 — mention 2-3 specific skills from Smit\'s resume that directly match this job\'s requirements. Be concrete, not vague.\n' +
          '4. Body paragraph 2 — one strong sentence about what value Smit brings to this specific company/role\n' +
          '5. Closing — short, confident call to action. Mention resume is attached. Sign off as: Smit Chavda\n\n' +
          'LENGTH: 3-4 short paragraphs, 150 to 200 words total.\n\n' +
          'STYLE RULES:\n' +
          '✅ Warm, direct, human tone — reads like a real person wrote it, not a template\n' +
          '✅ Every email is uniquely written for this specific company\n' +
          '✅ Active voice throughout\n' +
          '✅ Confident but not arrogant\n\n' +
          'FORBIDDEN:\n' +
          '❌ "I am writing to express my interest"\n' +
          '❌ "I came across your job posting"\n' +
          '❌ "Please find attached" or "Please find my resume attached"\n' +
          '❌ "I would love the opportunity"\n' +
          '❌ Any match %, scores, or analysis metadata\n' +
          '❌ "Role: X | Match: Y%" or similar internal labels\n' +
          '❌ Any HTML tags or special formatting characters\n' +
          '❌ Fake company facts not present in the job description\n' +
          '❌ A generic subject like "Job Application" or "Application for [Role]"\n\n' +
          'Required JSON output — exactly this structure, nothing else:\n' +
          '{\n' +
          '  "hr_email": "careers@company.com",\n' +
          '  "email_confidence": "high",\n' +
          '  "email_subject": "Your compelling subject line here",\n' +
          '  "email_body": "Opening sentence.\\n\\nParagraph about skills and match.\\n\\nValue statement.\\n\\nClosing sentence. Resume attached.\\n\\nBest regards,\\nSmit Chavda"\n' +
          '}',
        messages: [{
          role: 'user',
          content:
            'Company Name: ' + company + '\n' +
            'Job Title: ' + jobTitle + '\n' +
            'Location: ' + location + '\n' +
            'Salary: ' + salary + '\n' +
            'Job Type: ' + jobType + '\n' +
            'Company Website: ' + website + '\n' +
            'Company Domain: ' + domain + '\n' +
            'Job URL: ' + jobUrl + '\n\n' +
            'Job Description:\n' + jobDesc + '\n\n' +
            'Candidate Resume — Smit Chavda:\n' + resumeSnippet
        }]
      })
    });

    const data = await response.json();
    const rawText = str(data?.content?.[0]?.text);

    const fi = rawText.indexOf('{');
    const li = rawText.lastIndexOf('}');
    if (fi !== -1 && li !== -1) {
      try { aiResult = JSON.parse(rawText.substring(fi, li + 1)); } catch(e) {}
    }

    // Regex fallback for each field
    const extract = (field) => {
      const m = rawText.match(new RegExp('"' + field + '"\\s*:\\s*"((?:[^"\\\\]|\\\\.)*)"'));
      return m ? m[1].replace(/\\n/g,'\n').replace(/\\"/g,'"').trim() : '';
    };

    aiResult.hr_email         = str(aiResult.hr_email)         || extract('hr_email');
    aiResult.email_subject    = str(aiResult.email_subject)    || extract('email_subject');
    aiResult.email_body       = str(aiResult.email_body)       || extract('email_body');
    aiResult.email_confidence = str(aiResult.email_confidence) || extract('email_confidence') || 'medium';

  } catch(e) {
    results.push({
      json: {
        _error: true,
        _errorMsg: 'Claude API failed: ' + e.message,
        company, job_title: jobTitle, job_url: jobUrl
      }
    });
    continue;
  }

  const finalEmail = str(aiResult.hr_email) || (domain ? 'careers@' + domain : '');
  const bodyPlain  = str(aiResult.email_body);

  if (!finalEmail) {
    results.push({ json: { _error: true, _errorMsg: 'No hr_email found', company, job_title: jobTitle, job_url: jobUrl } });
    continue;
  }
  if (!bodyPlain) {
    results.push({ json: { _error: true, _errorMsg: 'Empty email body', company, job_title: jobTitle, job_url: jobUrl } });
    continue;
  }

  // Plain text → HTML
  const paras = bodyPlain
    .split(/\n{2,}/)
    .map(p => p.replace(/\n/g,' ').trim())
    .filter(p => p.length > 0);

  const htmlBody =
    '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.7;color:#1a1a1a;max-width:580px;">'
    + paras.map(p => '<p style="margin:0 0 18px 0;">' + p + '</p>').join('')
    + '</div>';

  results.push({
    json: {
      to_email:         finalEmail,
      email_subject:    str(aiResult.email_subject) || ('Application for ' + jobTitle + ' – Smit Chavda'),
      email_html:       htmlBody,
      email_confidence: str(aiResult.email_confidence),
      company,
      job_title:        jobTitle,
      job_url:          jobUrl,
      location,
      salary
    }
  });
}

return results;

const d = $json;
return [{ json: {
  _matchKey:     d.company || '',
  'Send Status': 'Skipped – ' + (d._errorMsg || 'AI failed'),
  'Recruiter Email': '',
  'Email Sent Date': new Date().toISOString()
} }];

const src = $('IF: Has Valid Email?').item.json;
return [{ json: {
  _matchKey:         src.company || '',
  'Send Status':     'Sent',
  'Recruiter Email': src.to_email || '',
  'Email Sent Date': new Date().toISOString()
} }];

const src = $('IF: Has Valid Email?').item.json;
const errMsg = $json?.error?.message || 'Gmail send failed after retries';
return [{ json: {
  _matchKey:         src.company || '',
  'Send Status':     'Failed – ' + errMsg,
  'Recruiter Email': src.to_email || '',
  'Email Sent Date': new Date().toISOString()
} }];
